SELECT material_name, AVG(thermal_conductivity) AS avg_thermal_conductivity
FROM material_types
GROUP BY material_name;

SELECT specimen_name, thickness
FROM specimens
WHERE specimen_id = 1;

SELECT material_name, density
FROM material_types
ORDER BY density DESC;

SELECT process_name, energy_input
FROM welding_processes
WHERE energy_input > 0.4;
